wp:postmeta.wp:meta_value:
/* Hide the image on desktop and tablets */
.image-responsive {
    display: none;
}

/* Show the image only on mobile devices */
@media (max-width: 768px) {
    .image-responsive {
        display: block;
    }
}


/* Hide the image on mobile devices */
.image-desktop {
    display: none;
}

/* Show the image on desktops and tablets */
@media (min-width: 769px) {
    .image-desktop {
        display: block;
    }
}

